import re

def parse_dsl(input_str):
    # Dsl parsing case handlers
    def parse_assignment(match):
        target, value = match[1].strip(), int(match[2].strip())
        return {"type": "Assignment", "target": target, "value": value}

    def parse_block(match):
        body = match[1].strip().split(";")
        body = [process_statement(block.strip()) for block in body if block and ";" not in block]
        return {"type": "Block", "body": body}

    def process_statement(statement):
        if statement.strip().startswith("SET"):
            match = re.match(r"SET\s+(\w+)\s+=\s+(\d+)", statement)
            if match:
                return parse_assignment(match)
        elif statement.strip().startswith("BLOCK {"):
            match = re.match(r"BLOCK\s+\{(.+)\}", statement, re.DOTALL)
            if match:
                return parse_block(match)
        return None

    # Parsed dictionary of the DSL
    parsed_dict = process_statement(input_str)

